// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Wire hooks auto-generated from data contract (none required for this component)
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Helper: Map weather condition to emoji icon
  const getWeatherEmoji = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌡️'; // Default
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Loading State */}
        {loading && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)" align="center" justify="center">
              <Spinner size={32} />
              <Text>Loading weather data...</Text>
            </Stack>
          </Card>
        )}

        {/* Error State */}
        {error && (
          <Alert variant="error" title="Weather Error" closable onClose={() => setError(null)}>
            {error}
          </Alert>
        )}

        {/* Main Weather Card */}
        {!loading && !error && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              {/* City and Date Header */}
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>

              {/* Main Temperature and Condition Section */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="center" justify="start">
                {/* Weather Icon (Large) */}
                <Box>
                  <Text size="4xl" role="img" aria-label={`${props.condition} weather icon`}>{getWeatherEmoji(props.condition)}</Text>
                </Box>

                {/* Temperature and Condition */}
                <Stack gap="var(--ggui-spacing-2)" align="start">
                  <Heading level={2} color="var(--ggui-color-primary-600)" align="left">
                    {props.temperature}°{props.unit}
                  </Heading>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)" aria-label="Current weather condition">
                    {props.condition}
                  </Text>
                </Stack>
              </Stack>
              {/* Divider */}
              <Divider margin="var(--ggui-spacing-4)" />

              {/* Humidity and Wind Speed Section */}
              <Row gap="var(--ggui-spacing-6)" justify="between" align="stretch">
                {/* Humidity */}
                <Stack gap="var(--ggui-spacing-2)" align="start">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Humidity
                  </Text>
                  <Heading level={4} color="var(--ggui-color-onSurface)">{props.humidity}%</Heading>
                </Stack>

                {/* Wind Speed */}
                <Stack gap="var(--ggui-spacing-2)" align="start">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Wind Speed
                  </Text>
                  <Heading level={4} color="var(--ggui-color-onSurface)">{props.windSpeed} {props.unit === 'C' ? 'km/h' : 'mph'}</Heading>
                </Stack>
              </Row>
           </Card>
        )}
        {/* 5-Day Forecast Section */}
        {!loading && !error && props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3} color="var(--ggui-color-onSurface)">
                5-Day Forecast
              </Heading>

              {/* Forecast Strip */}
              <Row gap="var(--ggui-spacing-4)" justify="between" align="stretch" wrap>
                {props.forecast.map((day, index) => (
                  <Box
                    key={index}
                    role="listitem"
                    style={{
                      flex: '1 1 auto',
                      minWidth: '80px',
                      padding: 'var(--ggui-spacing-4)',
                      border: '1px solid var(--ggui-color-outlineVariant)',
                      borderRadius: 'var(--ggui-shape-radius-md)',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      justifyContent: 'center',
                      gap: 'var(--ggui-spacing-2)'
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      {/* Day Name */}
                      {day.day && (
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">
                          {day.day}
                        </Text>
                      )}

                      {/* Icon / Emoji */}
                      {day.icon && (
                        <Text size="2xl" role="img" aria-label={`Weather icon for ${day.day}`}>{day.icon}</Text>
                      )}

                      {/* High / Low Temps */}
                      <Stack gap="var(--ggui-spacing-1)" align="center" aria-label="High and low temperatures">
                        {day.high !== undefined && (
                          <Text variant="body" color="var(--ggui-color-onSurface)" align="center" weight="semibold">
                            {day.high}°
                          </Text>
                        )}
                        {day.low !== undefined && (
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
                            {day.low}°
                          </Text>
                        )}
                      </Stack>
                    </Stack>
                  </Box>
                ))}
              </Row>
            </Stack>
          </Card>
        )}

        {/* Empty Forecast State */}
        {!loading && !error && (!props.forecast || props.forecast.length === 0) && (
          <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="lg">
            <Text color="var(--ggui-color-onSurfaceVariant)" align="center">
              No forecast available
            </Text>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for all form fields
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  const nameError = currentStep === 1 && name.trim() === '' ? 'Name is required' : '';
  const emailError = currentStep === 1 && (email.trim() === '' || !isValidEmail(email)) ? 'Valid email is required' : '';

  const isStep1Valid = name.trim() !== '' && email.trim() !== '' && isValidEmail(email);
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = features.length > 0;

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep === 3 && !isStep3Valid) return;
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid, isStep3Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    if (name.trim() === '' || email.trim() === '' || !isValidEmail(email)) return;
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction),
      features,
      comments: comments.trim(),
    });
  }, [name, email, satisfaction, features, comments, submit]);

  const handleFeatureToggle = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  };

  // Generate satisfaction radio options from labels
  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Progress Bar */}
        {/* Progress Bar */}
        <Box aria-label={`Survey progress: Step ${currentStep} of 4`}>
          <Stack gap="var(--ggui-spacing-4)" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of 4
            </Text>
            <Progress value={currentStep} max={4} size="md" variant="default" />
          </Stack>
        </Box>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Personal Information</Heading>
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  required
                  value={name}
                  onChange={setName}
                  placeholder="John Doe"
                  error={nameError}
                />
                <Input
                  label="Email"
                  required
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="john@example.com"
                  error={emailError}
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <Text variant="body">How satisfied are you with our service?</Text>
              <RadioGroup
                label="Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="body">Which features are you most interested in?</Text>
              <Stack gap="var(--ggui-spacing-3)" align="start">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Additional Comments</Heading>
              <Text variant="body">Any other feedback or comments?</Text>
              <TextArea
                label="Comments"
                value={comments}
                onChange={setComments}
                placeholder="Share your thoughts here..."
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Final Review (Step 5) */}
        {currentStep === 5 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Review Your Answers</Heading>

              <Box background="var(--ggui-color-primary-50)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-4)">
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Name
                    </Text>
                    <Text variant="body">{name}</Text>
                  </Box>
                  <Divider />
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Email
                    </Text>
                    <Text variant="body">{email}</Text>
                  </Box>
                  <Divider />
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body">
                      {satisfaction ? props.satisfactionLabels[parseInt(satisfaction) - 1] : 'Not selected'}
                    </Text>
                  </Box>
                  <Divider />
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Interested Features
                    </Text>
                    <Stack gap="var(--ggui-spacing-2)" direction="horizontal" wrap>
                      {features.map((feature) => (
                        <Badge key={feature} variant="primary">
                          {feature}
                        </Badge>
                      ))}
                    </Stack>
                  </Box>
                  {comments && (
                    <>
                      <Divider />
                      <Box>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                          Comments
                        </Text>
                        <Text variant="body">{comments}</Text>
                      </Box>
                    </>
                  )}
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid) ||
                (currentStep === 3 && !isStep3Valid)
              }
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

