import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messageText, setMessageText] = useState<string>('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [activeTyper, setActiveTyper] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on new messages
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, activeTyper, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setActiveTyper(typing.latest.sender || null);
      } else {
        setActiveTyper(null);
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      sendMessage({
        text: messageText,
        timestamp: new Date().toISOString(),
      });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  // Handle Enter key to send
  // Handle Enter key to send
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Format timestamp for display
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg] });
      }
    });

    return groups;
  }, [allMessages]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="0" radius="lg" style={{ display: 'flex', flexDirection: 'column', height: '100vh', maxHeight: '100vh' }}>
        {/* Header */}
        <Box
          paddingX="var(--ggui-spacing-6)"
          paddingY="var(--ggui-spacing-4)"
          background="var(--ggui-color-primary-50, #f0f9ff)"
          style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3} color="var(--ggui-color-primary-900, #0c4a6e)">{props.title}</Heading>
              <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
            </Stack>
            {activeTyper && (
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{activeTyper} is typing...</Text>
              </Stack>
            )}
          </Stack>
        </Box>

        {/* Messages Area */}
        <Box
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack gap="var(--ggui-spacing-4)" align="stretch">
            {groupedMessages.map((group, groupIdx) => {
              const isCurrentUser = group.sender === props.currentUser;
              return (
                <Stack
                  key={groupIdx}
                  gap="var(--ggui-spacing-2)"
                  align={isCurrentUser ? 'end' : 'start'}
                  style={{ maxWidth: '70%', alignSelf: isCurrentUser ? 'flex-end' : 'flex-start' }}
                >
                  {group.messages.map((msg, msgIdx) => (
                    <Card
                      key={msgIdx}
                      padding="var(--ggui-spacing-3)"
                      shadow="sm"
                      radius="md"
                      style={{
                        background: isCurrentUser
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        border: 'none',
                      }}
                    >
                      <Stack gap="var(--ggui-spacing-1)" align="stretch">
                        <Text
                          variant="bodySmall"
                          weight="semibold"
                          color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        >
                          {group.sender || 'Unknown'}
                        </Text>
                        <Text
                          variant="body"
                          color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface, #18181b)'}
                          style={{ wordBreak: 'break-word' }}
                        >
                          {msg.text || ''}
                        </Text>
                        <Text
                          variant="caption"
                          color={isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                          align="right"
                        >
                          {formatTime(msg.timestamp)}
                        </Text>
                      </Stack>
                    </Card>
                  ))}
                </Stack>
              );
            })}
            <div ref={messagesEndRef} />
          </Stack>
        </Box>

        {/* Input Area */}
        <Box
          paddingX="var(--ggui-spacing-4)"
          paddingY="var(--ggui-spacing-4)"
          background="var(--ggui-color-surface, #fafafa)"
          style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                value={messageText}
                onChange={setMessageText}
                placeholder="Type your message here..."
                onKeyDown={handleKeyDown}
              />
            </Box>
            <Button
              variant="primary"
              size="md"
              onClick={handleSendMessage}
              disabled={!messageText.trim()}
              rightIcon={<Icon name="send" size={16} />}
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

