/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  // State: merged stock data (initial + live updates)
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const [selectedSymbol, setSelectedSymbol] = useState<string | null>(null);
  const animationTimeoutRef = useRef<NodeJS.Timeout>();
  const lastUpdatedIntervalRef = useRef<NodeJS.Timeout>();

  // Effect: merge live price updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        return prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            // Mark this stock for flash animation
            setHighlightedSymbols((prev) => {
              const next = new Set(prev);
              next.add(update.symbol!);
              return next;
            });

            // Clear highlight after animation duration
            if (animationTimeoutRef.current) {
              clearTimeout(animationTimeoutRef.current);
            }
            animationTimeoutRef.current = setTimeout(() => {
              setHighlightedSymbols((prev) => {
                const next = new Set(prev);
                next.delete(update.symbol!);
                return next;
              });
            }, 600); // Match animation duration

            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
      });
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Effect: update Last Updated timestamp in real-time (every 100ms)
  useEffect(() => {
    lastUpdatedIntervalRef.current = setInterval(() => {
      setLastUpdated(new Date());
    }, 100);
    return () => {
      if (lastUpdatedIntervalRef.current) {
        clearInterval(lastUpdatedIntervalRef.current);
      }
    };
  }, []);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (animationTimeoutRef.current) {
        clearTimeout(animationTimeoutRef.current);
      }
    };
  }, []);
  // Helper: format price with 2 decimals
  const formatPrice = (price?: number): string => {
    if (price === undefined || price === null) return 'N/A';
    return price.toFixed(2);
  };

  // Helper: get color for change value
  const getChangeColor = (change?: number): string => {
    if (change === undefined || change === null) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    return change >= 0 ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
  };

  // Helper: get arrow icon for change
  const getChangeArrow = (change?: number): string => {
    if (change === undefined || change === null) return '—';
    return change >= 0 ? '▲' : '▼';
  };

  // Helper: get border color for card
  const getCardBorderColor = (change?: number): string => {
    if (change === undefined || change === null) return 'var(--ggui-color-outlineVariant, #e4e4e7)';
    return change >= 0 ? 'var(--ggui-color-success-200, #bbf7d0)' : 'var(--ggui-color-error-200, #fecaca)';
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding={24}>
        <Stack gap={24} direction="vertical">
          {/* Header */}
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
