            <Stack direction="horizontal" align="center" gap={8}>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated:{' '}
                <Text as="span" weight="semibold" variant="bodySmall">
                  {lastUpdated.toLocaleTimeString()}
                </Text>
              </Text>
            </Stack>
          </Stack>

          {/* Stock Cards Grid */}
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: '24px',
            } as React.CSSProperties}
          >
            {stocks && stocks.length > 0 ? (
              stocks.map((stock) => {
                const isHighlighted = highlightedSymbols.has(stock.symbol || '');
                const changeColor = getChangeColor(stock.change);
                const cardBorderColor = getCardBorderColor(stock.change);
                const arrowIcon = getChangeArrow(stock.change);
                const isSelected = selectedSymbol === stock.symbol;

                return (
                  <Card
                    key={stock.symbol || Math.random()}
                    padding={16}
                    shadow="md"
                    radius="lg"
                    as={Clickable}
                    onClick={() => setSelectedSymbol(isSelected ? null : stock.symbol || null)}
                    role="article"
                    aria-label={`${stock.symbol || 'Stock'}: ${stock.change !== undefined && stock.change !== null ? (stock.change >= 0 ? 'positive' : 'negative') : 'neutral'} change of ${stock.changePercent ? stock.changePercent.toFixed(2) + '%' : 'N/A'}`}
                    style={{
                      border: `2px solid ${cardBorderColor}`,
                      transition: 'all 0.3s ease',
                      backgroundColor: isHighlighted
                        ? 'var(--ggui-color-primary-50, #f0f9ff)'
                        : isSelected
                        ? 'var(--ggui-color-primary-100, #e0f2fe)'
                        : 'var(--ggui-color-surface, #ffffff)',
                      transform: isHighlighted ? 'scale(1.02)' : isSelected ? 'scale(1.01)' : 'scale(1)',
                      animation: isHighlighted ? 'ggui-scaleIn 0.6s ease-out' : 'none',
                      cursor: 'pointer',
                    } as React.CSSProperties}
                  >
                    <Stack gap={12} direction="vertical">
                      {/* Ticker Symbol and Company Name */}
                      <Stack direction="vertical" gap={4}>
                        <Heading
                          level={2}
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {stock.symbol || 'N/A'}
                        </Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {stock.name || '—'}
                        </Text>
                      </Stack>

                      <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                      {/* Price */}
                      <Stack direction="vertical" gap={4}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
                          Current Price
                        </Text>
                        <Text
                          variant="bodyLarge"
                          color="var(--ggui-color-onSurface, #18181b)"
                          weight="semibold"
                        >
                          ${formatPrice(stock.price)}
                        </Text>
                      </Stack>

                    {/* Change Amount and Percentage */}
                      {/* Change Amount and Percentage */}
                      <Stack direction="horizontal" gap={12} align="center">
                        <Stack direction="vertical" gap={4} align="start">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
                            Change
                          </Text>
                          <Text variant="body" color={changeColor} weight="semibold">
                            {stock.change !== undefined && stock.change !== null
                              ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2)
                              : '—'}
                          </Text>
                        </Stack>
                        <Stack direction="vertical" gap={4} align="start">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
                            Change %
                          </Text>
                          <Stack direction="horizontal" gap={4} align="center">
                            <Text variant="body" color={changeColor} weight="semibold">
                              {stock.changePercent !== undefined && stock.changePercent !== null
                                ? (stock.changePercent >= 0 ? '+' : '') + stock.changePercent.toFixed(2) + '%'
                                : '—'}
                            </Text>
                            <Text
                              variant="body"
                              color={changeColor}
                              weight="bold"
                              role="img"
                              aria-label={stock.change !== undefined && stock.change !== null ? (stock.change >= 0 ? 'up arrow' : 'down arrow') : 'no change'}
                            >
                              {arrowIcon}
                            </Text>
                          </Stack>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Card>
                );
              })
            ) : (
              <Box
                padding={32}
                style={{
                  gridColumn: '1 / -1',
                  textAlign: 'center',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                } as React.CSSProperties}
              >
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  No stocks available
                </Text>
              </Box>
            )}
          </Box>
        </Stack>
      </Container>
    </>
  );

}

