// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0]);
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications !== false);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark');

  // Validation
  const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  const nameError = currentStep === 1 && !name ? 'Name is required' : '';
  const emailError = currentStep === 1 && (!email || !isValidEmail(email)) ? 'Valid email is required' : '';
  const roleError = currentStep === 2 && !role ? 'Please select a role' : '';

  const isStep1Valid = name && isValidEmail(email);
  const isStep2Valid = role;

  const handleNext = () => {
    if (currentStep === 1 && isStep1Valid) {
      setCurrentStep(2);
    } else if (currentStep === 2 && isStep2Valid) {
      setCurrentStep(3);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep((currentStep - 1) as 1 | 2 | 3);
    }
  };

  const handleComplete = () => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme: theme ? 'dark' : 'light',
    });
  };

  // Role options for dropdown
  const roleSelectOptions = props.roleOptions.map((r) => ({ value: r, label: r }));

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap={"var(--ggui-spacing-8)"} align="center">
        {/* Step Indicator */}
        <Box width="100%">
          <Stack gap={"var(--ggui-spacing-4)"}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3}>Profile Setup</Heading>
              <Text variant="label">Step {currentStep} of 3</Text>
            </Stack>
            <Progress
              value={currentStep * 33.33}
              max={100}
              size="md"
              variant="default"
            />
          </Stack>
        </Box>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" width="100%">
            <Stack gap={"var(--ggui-spacing-6)"}>
              <Heading level={2}>Personal Information</Heading>

              <Input
                label="Full Name"
                placeholder="Enter your full name"
                value={name}
                onChange={setName}
                required
                error={nameError}
              />

              <Input
                label="Email Address"
                type="email"
                placeholder="your@email.com"
                value={email}
                onChange={setEmail}
                required
                error={emailError}
              />

              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Select Avatar</Text>
                <Spacer size={"var(--ggui-spacing-2)"} />
                <Stack direction="horizontal" gap={"var(--ggui-spacing-4)"} wrap>
                  {props.avatarOptions.map((emojiAvatar) => (
                    <Box
                      key={emojiAvatar}
                      as={Clickable}
                      onClick={() => setAvatar(emojiAvatar)}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={avatar === emojiAvatar ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{
                        border: avatar === emojiAvatar ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent',
                        transition: 'all 200ms ease-in-out',
                        cursor: 'pointer',
                        fontSize: '32px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        minWidth: '56px',
                        minHeight: '56px',
                      }}
                    >
                      {emojiAvatar}
                    </Box>
                  ))}
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" width="100%">
            <Stack gap={"var(--ggui-spacing-6)"}>
              <Heading level={2}>Preferences</Heading>

              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={roleSelectOptions}
                placeholder="Select your role"
                required
                error={roleError}
              />

              <Divider />

              <Stack gap={"var(--ggui-spacing-4)"}>
                <Toggle
                  label="Email Notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Receive email updates about your account and activity
                </Text>
              </Stack>

              <Stack gap={"var(--ggui-spacing-4)"}>
                <Toggle
                  label={theme ? 'Dark Theme' : 'Light Theme'}
                  checked={theme}
                  onChange={setTheme}
                  size="md"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Choose your preferred color scheme
                </Text>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" width="100%">
            <Stack gap={"var(--ggui-spacing-6)"}>
              <Heading level={2}>Review Your Profile</Heading>

              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap={"var(--ggui-spacing-4)"}>
                  <Stack direction="horizontal" align="center" gap={"var(--ggui-spacing-3)"}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar:</Text>
                    <Text variant="body" style={{ fontSize: '24px' }}>{avatar}</Text>
                  </Stack>

                  <Stack gap={"var(--ggui-spacing-2)"}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                    <Text variant="body">{name}</Text>
                  </Stack>

                  <Stack gap={"var(--ggui-spacing-2)"}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                    <Text variant="body">{email}</Text>
                  </Stack>

                  <Divider margin={"var(--ggui-spacing-2)"} />

                  <Stack gap={"var(--ggui-spacing-2)"}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                    <Text variant="body">{role}</Text>
                  </Stack>

                  <Stack gap={"var(--ggui-spacing-2)"}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text>
                    <Badge variant={emailNotifications ? 'success' : 'secondary'}>
                      {emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Stack>

                  <Stack gap={"var(--ggui-spacing-2)"}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                    <Badge variant="primary">
                      {theme ? 'Dark' : 'Light'}
                    </Badge>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Box width="100%">
          <Stack direction="horizontal" justify="between" gap={"var(--ggui-spacing-4)"}>
            <Button
              variant="outline"
              onClick={handleBack}
              disabled={currentStep === 1}
            >
              Go Back
            </Button>

            {currentStep < 3 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={
                  (currentStep === 1 && !isStep1Valid) ||
                  (currentStep === 2 && !isStep2Valid)
                }
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleComplete}
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}
}
